import './Autocomplete.scss';

import { Button } from ':components/Button';
import { Chip } from ':components/Chip';
import { MaskField } from ':components/MaskField';
import { Modal } from ':components/Modal';
import type { NewDropdownMenuProps } from ':components/NewDropdownMenu';
import { NewDropdownMenu } from ':components/NewDropdownMenu';
import { Typography } from ':components/Typography';
import { useDeviceSize } from ':helpers';
import { classNames } from ':helpers/classnames';
import type { ReactElement, Ref } from 'react';
import React, { forwardRef, useImperativeHandle } from 'react';

import { Search } from '../Search';
import { TextField } from '../TextField';
import type { AutocompleteProps } from './Autocomplete.types';
import { useAutocomplete } from './useAutocomplete';

export const Autocomplete = forwardRef(
	<T,>(
		{
			size,
			value,
			onChange,
			defaultValue,
			dropdownClassName,
			dropdownElementID,
			onClose,
			onOpen,
			open,
			children,
			onFocus,
			onBlur,
			onSubmit,
			onClick,
			options,
			fullWidth,
			className,
			disabled,
			defaultGroupID,
			renderValue,
			onInputChange,
			onInputClear,
			onFilterChange,
			filterItems,
			selectedFilter,
			enableGrouping = false,
			makeOption,
			label,
			type,
			showTooltip = false,
			noOptionsText,
			noOptionsContents,
			loading,
			loadingText,
			loadingContent,
			hideDropDown = false,
			dataTestId = 'Autocomplete',
			enableKeyboardNavigation = false,
			maskConfig,
			overlayScroll = true,
			shouldRenderOverlay,
			overlayClassName,
			alignDropDown,
			mobileTitle = 'Поиск',
			mobileCaption = 'Результаты поиска',
			applicationRootElementID = 'root',
			classNameMobileModal,
			...props
		}: AutocompleteProps<T>,
		ref: Ref<HTMLInputElement>,
	): React.JSX.Element => {
		const { isExtraSmallDevice } = useDeviceSize();
		const {
			isOpen,
			innerRef,
			handleClose,
			setOpen,
			handleMaskInputOnChange,
			handleInputClick,
			handleInputBlur,
			handleInputFocus,
			inputValue,
			handleInputOnChange,
			handleInputOnClear,
			rootClassName,
			handleKeyDown,
			isSearch,
			optionsComponents,
		} = useAutocomplete({
			type,
			value,
			open,
			renderValue,
			enableKeyboardNavigation,
			onOpen,
			onClose,
			onChange,
			onFocus,
			onBlur,
			onInputChange,
			onInputClear,
			showTooltip,
			loading,
			loadingText,
			loadingContent,
			hideDropDown,
			options,
			noOptionsContents,
			noOptionsText,
			makeOption,
			className,
			isExtraSmallDevice,
		});

		useImperativeHandle(ref, () => innerRef.current);

		const dropdownMenuProps: NewDropdownMenuProps = {
			targetElement: innerRef,
			align: alignDropDown,
			verticalOffset: 1,
			applicationRootElementID,
			dropdownElementID,
			className: dropdownClassName,
			isOpen,
			handleSetOpen: setOpen,
			overlayScroll,
			shouldRenderOverlay,
			overlayClassName,
		};

		const makeDropdownView = (mobileOptions = false): ReactElement =>
			maskConfig ? (
				<MaskField
					{...props}
					ref={innerRef}
					label={label}
					size={size}
					fullWidth={fullWidth || mobileOptions}
					maskConfig={maskConfig}
					onChange={handleMaskInputOnChange}
					onBlur={handleInputBlur}
					onClick={handleInputClick}
					onFocus={handleInputFocus}
					disabled={disabled}
					value={inputValue}
					contentEditable={true}
					dataTestId={dataTestId + '-textField'}
				/>
			) : (
				<TextField
					{...props}
					ref={innerRef}
					label={label}
					size={size}
					fullWidth={fullWidth || mobileOptions}
					onChange={handleInputOnChange}
					onBlur={handleInputBlur}
					onFocus={handleInputFocus}
					onClick={handleInputClick}
					disabled={disabled}
					value={inputValue}
					contentEditable={true}
					dataTestId={dataTestId + '-textField'}
				/>
			);

		const makeSearchView = (mobileOptions = false): ReactElement => {
			const filterByGroupProps =
				enableGrouping && !mobileOptions && !isExtraSmallDevice ? { filterItems, selectedFilter, onFilterChange } : {};

			return (
				<Search
					{...props}
					{...filterByGroupProps}
					ref={innerRef}
					size={size}
					fullWidth={fullWidth || mobileOptions}
					onBlur={handleInputBlur}
					onFocus={handleInputFocus}
					onChange={handleInputOnChange}
					onClear={handleInputOnClear}
					disabled={disabled}
					value={inputValue}
					contentEditable={false}
					dataTestId={dataTestId + '-search'}
				/>
			);
		};

		const makeMobileView = () => (
			<Modal className={classNameMobileModal} applicationRootElement={applicationRootElementID} open={true}>
				<div className="dsb__autocomplete-mobile">
					<Typography variant="subtitle1">{mobileTitle}</Typography>
					<div className="dsb__autocomplete-mobile__component">
						{isSearch ? makeSearchView(true) : makeDropdownView(true)}
						<Button
							variant="plain"
							onClick={() => {
								handleClose();
							}}
						>
							Закрыть
						</Button>
					</div>
					<div className="dsb__autocomplete-mobile__chips">
						{filterItems?.map(item => (
							<Chip
								id={String(item.id)}
								label={item.value}
								active={selectedFilter === item}
								onClick={() => onFilterChange(item)}
							/>
						))}
					</div>
					<Typography className="dsb__autocomplete-mobile__caption" variant="caption">
						{mobileCaption}
					</Typography>
					{optionsComponents}
				</div>
			</Modal>
		);

		const makeOptionsView = (): ReactElement =>
			isExtraSmallDevice ? (
				makeMobileView()
			) : (
				<NewDropdownMenu {...dropdownMenuProps}>{optionsComponents}</NewDropdownMenu>
			);

		return (
			<div
				data-testid={dataTestId}
				className={classNames(rootClassName)}
				onKeyDown={enableKeyboardNavigation ? handleKeyDown : () => {}}
			>
				{isSearch ? makeSearchView() : makeDropdownView()}
				{isOpen && !hideDropDown && makeOptionsView()}
			</div>
		);
	},
) as <T>(props: AutocompleteProps<T> & { ref?: Ref<HTMLInputElement> }) => React.JSX.Element;
